import React, { useState, useRef } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { Search, Menu, X, Heart, Play, TrendingUp } from 'lucide-react';

const App = () => {
  const [page, setPage] = useState('landing');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [scanInput, setScanInput] = useState('');
  const [scanResults, setScanResults] = useState([]);
  const [selectedStock, setSelectedStock] = useState(null);
  const [loading, setLoading] = useState(false);
  const [watchlist, setWatchlist] = useState([]);
  const [activeFilter, setActiveFilter] = useState('all');
  const [chartData, setChartData] = useState([]);
  const [lines, setLines] = useState([]);
  const [isDrawing, setIsDrawing] = useState(false);
  const [drawMode, setDrawMode] = useState(null);
  const canvasRef = useRef(null);
  const [startPoint, setStartPoint] = useState(null);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const filters = [
    { id: 'all', label: 'All Stocks', icon: '📊' },
    { id: 'momentum', label: 'Momentum Play', icon: '🚀' },
    { id: 'breakout', label: 'Breakouts', icon: '📈' },
    { id: 'oversold', label: 'Oversold Bounce', icon: '⬆️' },
    { id: 'gap-up', label: 'Gap Up Movers', icon: '⚡' },
    { id: 'volume-spike', label: 'Volume Spike', icon: '📢' },
    { id: 'earnings', label: 'Earnings Play', icon: '💼' },
    { id: 'watchlist', label: 'My Watchlist', icon: '❤️' }
  ];

  const generateStockData = (ticker) => ({
    ticker: ticker.toUpperCase(),
    price: (Math.random() * 200 + 20).toFixed(2),
    change: ((Math.random() - 0.5) * 30).toFixed(2),
    percentChange: ((Math.random() - 0.5) * 15).toFixed(2),
    volume: (Math.random() * 100000000).toFixed(0),
    rsi: (Math.random() * 100).toFixed(1),
    macd: (Math.random() - 0.5).toFixed(3),
    signal: (Math.random() * 100).toFixed(0),
    momentum: ((Math.random() - 0.5) * 200).toFixed(1),
    range: ((Math.random() * 30)).toFixed(1),
    consolDays: Math.floor(Math.random() * 30),
    pe_ratio: (Math.random() * 40 + 5).toFixed(2),
    dayHigh: (Math.random() * 200 + 100).toFixed(2),
    dayLow: (Math.random() * 100 + 50).toFixed(2),
    gapUp: Math.random() > 0.7,
    volumeSpike: Math.random() > 0.6,
    breakout: Math.random() > 0.5,
    oversold: Math.random() > 0.7
  });

  const generateChartData = () => {
    return Array.from({ length: 48 }, (_, i) => ({
      time: `${Math.floor(i / 2)}:${(i % 2) * 30}`,
      price: Math.random() * 50 + 100
    }));
  };

  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const url = isSignUp ? 'http://localhost:5001/api/auth/register' : 'http://localhost:5001/api/auth/login';
      const res = await fetch(url, { 
        method: 'POST', 
        headers: { 'Content-Type': 'application/json' }, 
        body: JSON.stringify(isSignUp ? { email, password, name } : { email, password }) 
      });
      const data = await res.json();
      if (data.token) {
        localStorage.setItem('token', data.token);
        setIsLoggedIn(true);
        setPage('app');
      } else {
        alert('Error: ' + (data.error || 'Failed'));
      }
    } catch (err) {
      alert('Error: ' + err.message);
    }
    setLoading(false);
  };

  const handleScan = async (e) => {
    e.preventDefault();
    setLoading(true);
    const tickers = scanInput.split(',').map(t => t.trim());
    const token = localStorage.getItem('token');
    try {
      const res = await fetch('http://localhost:5001/api/scan', { 
        method: 'POST', 
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token }, 
        body: JSON.stringify({ tickers }) 
      });
      const data = await res.json();
      const enhanced = (data.results || []).map(r => ({ ...r, ...generateStockData(r.ticker) }));
      setScanResults(enhanced);
    } catch (err) {
      alert('Error: ' + err.message);
    }
    setLoading(false);
  };

  const toggleWatchlist = (ticker) => {
    if (watchlist.includes(ticker)) {
      setWatchlist(watchlist.filter(t => t !== ticker));
    } else {
      setWatchlist([...watchlist, ticker]);
    }
  };

  // LANDING PAGE
  if (page === 'landing') {
    return (
      <div style={{ background: 'linear-gradient(135deg, #0a0a14 0%, #1a1a2e 100%)', minHeight: '100vh', color: 'white', fontFamily: '"Segoe UI", Tahoma, Geneva, Verdana, sans-serif' }}>
        <nav style={{ background: 'rgba(10,10,20,0.9)', backdropFilter: 'blur(10px)', borderBottom: '1px solid rgba(100,200,255,0.1)', padding: '1.5rem 2rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <h1 style={{ margin: 0, fontSize: '26px', fontWeight: '800', background: 'linear-gradient(135deg, #00d9ff 0%, #0099ff 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>Bailey's Gauge</h1>
          <div style={{ display: 'flex', gap: '1rem' }}>
            <button onClick={() => { setIsSignUp(false); setPage('auth'); }} style={{ padding: '0.75rem 1.5rem', background: 'transparent', color: '#00d9ff', border: '2px solid #00d9ff', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: '14px', transition: 'all 0.3s' }}>Sign In</button>
            <button onClick={() => { setIsSignUp(true); setPage('auth'); }} style={{ padding: '0.75rem 1.5rem', background: 'linear-gradient(135deg, #00d9ff 0%, #0099ff 100%)', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: '14px' }}>Start Free</button>
          </div>
        </nav>

        <div style={{ maxWidth: '1400px', margin: '0 auto', padding: '5rem 2rem' }}>
          <h2 style={{ fontSize: '72px', fontWeight: '900', margin: '0 0 1.5rem', lineHeight: '1.1', background: 'linear-gradient(135deg, #00d9ff 0%, #0099ff 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>Day Trader's<br/>Trading Command Center</h2>
          <p style={{ fontSize: '20px', color: '#aaa', margin: '0 0 2rem', lineHeight: '1.6', maxWidth: '600px' }}>Real-time stock analysis. Technical patterns. Price action. All in one place. Find your next trade in seconds, not hours.</p>
          <button onClick={() => { setIsSignUp(true); setPage('auth'); }} style={{ padding: '1rem 2.5rem', background: 'linear-gradient(135deg, #00d9ff 0%, #0099ff 100%)', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: '16px', marginRight: '1rem', boxShadow: '0 20px 40px rgba(0,217,255,0.3)' }}>Launch Platform →</button>
          <button style={{ padding: '1rem 2.5rem', background: 'transparent', color: '#00d9ff', border: '2px solid #00d9ff', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: '16px' }}>Watch Demo ↓</button>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '2rem', marginTop: '5rem' }}>
            {[
              { icon: '⚙️', title: 'Smart Screeners', desc: 'Pre-built scans for every strategy' },
              { icon: '📊', title: 'Live Charts', desc: 'Professional-grade technical analysis' },
              { icon: '✏️', title: 'Drawing Tools', desc: 'Annotate trends and patterns' },
              { icon: '🎯', title: 'Signal Alerts', desc: 'Get notified of setup matches' },
              { icon: '❤️', title: 'Track Stocks', desc: 'Build and manage watchlists' },
              { icon: '⚡', title: 'Fast & Smooth', desc: 'Real-time updates, zero lag' }
            ].map((f, i) => (
              <div key={i} style={{ background: 'rgba(0,217,255,0.05)', border: '1px solid rgba(0,217,255,0.1)', padding: '2rem', borderRadius: '12px', cursor: 'pointer', transition: 'all 0.3s' }} onMouseEnter={(e) => { e.currentTarget.style.background = 'rgba(0,217,255,0.1)'; e.currentTarget.style.borderColor = 'rgba(0,217,255,0.3)'; }} onMouseLeave={(e) => { e.currentTarget.style.background = 'rgba(0,217,255,0.05)'; e.currentTarget.style.borderColor = 'rgba(0,217,255,0.1)'; }}>
                <div style={{ fontSize: '40px', marginBottom: '1rem' }}>{f.icon}</div>
                <h3 style={{ fontSize: '18px', fontWeight: '700', marginBottom: '0.5rem', color: 'white' }}>{f.title}</h3>
                <p style={{ color: '#aaa', fontSize: '14px', margin: 0 }}>{f.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  // AUTH PAGE
  if (page === 'auth') {
    return (
      <div style={{ background: 'linear-gradient(135deg, #0a0a14 0%, #1a1a2e 100%)', minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '2rem', fontFamily: '"Segoe UI", Tahoma, Geneva, Verdana, sans-serif' }}>
        <div style={{ maxWidth: '450px', width: '100%', background: 'rgba(26,26,46,0.8)', backdropFilter: 'blur(10px)', padding: '3rem', borderRadius: '12px', border: '1px solid rgba(0,217,255,0.1)' }}>
          <h2 style={{ textAlign: 'center', color: 'white', marginTop: 0, marginBottom: '2rem', fontSize: '28px', fontWeight: '700' }}>{isSignUp ? 'Create Account' : 'Sign In'}</h2>
          <form onSubmit={handleAuth}>
            {isSignUp && (
              <input type="text" placeholder="Full Name" value={name} onChange={(e) => setName(e.target.value)} style={{ width: '100%', padding: '0.875rem', marginBottom: '1rem', borderRadius: '8px', border: '1px solid rgba(0,217,255,0.2)', background: 'rgba(10,10,20,0.5)', color: 'white', fontSize: '14px', boxSizing: 'border-box' }} required />
            )}
            <input type="email" placeholder="Email Address" value={email} onChange={(e) => setEmail(e.target.value)} style={{ width: '100%', padding: '0.875rem', marginBottom: '1rem', borderRadius: '8px', border: '1px solid rgba(0,217,255,0.2)', background: 'rgba(10,10,20,0.5)', color: 'white', fontSize: '14px', boxSizing: 'border-box' }} required />
            <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} style={{ width: '100%', padding: '0.875rem', marginBottom: '2rem', borderRadius: '8px', border: '1px solid rgba(0,217,255,0.2)', background: 'rgba(10,10,20,0.5)', color: 'white', fontSize: '14px', boxSizing: 'border-box' }} required />
            <button type="submit" style={{ width: '100%', padding: '0.875rem', background: 'linear-gradient(135deg, #00d9ff 0%, #0099ff 100%)', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: '14px' }}>
              {loading ? 'Loading...' : (isSignUp ? 'Create Account' : 'Sign In')}
            </button>
          </form>
          <p style={{ textAlign: 'center', color: '#aaa', marginTop: '1.5rem', fontSize: '14px' }}>
            {isSignUp ? 'Already have an account? ' : "Don't have an account? "}
            <button onClick={() => setIsSignUp(!isSignUp)} style={{ background: 'none', border: 'none', color: '#00d9ff', cursor: 'pointer', fontWeight: '700' }}>{isSignUp ? 'Sign In' : 'Sign Up'}</button>
          </p>
        </div>
      </div>
    );
  }

  // MAIN APP
  if (page === 'app' && isLoggedIn) {
    return (
      <div style={{ background: 'linear-gradient(135deg, #0a0a14 0%, #1a1a2e 100%)', minHeight: '100vh', color: 'white', display: 'flex', fontFamily: '"Segoe UI", Tahoma, Geneva, Verdana, sans-serif' }}>
        {/* SIDEBAR */}
        {sidebarOpen && (
          <div style={{ width: '280px', background: 'rgba(26,26,46,0.8)', backdropFilter: 'blur(10px)', borderRight: '1px solid rgba(0,217,255,0.1)', padding: '2rem 0', overflowY: 'auto' }}>
            <h2 style={{ margin: '0 1.5rem 2rem', fontSize: '20px', fontWeight: '800', color: 'white' }}>Bailey's Gauge</h2>

            <div>
              <p style={{ margin: '0 1.5rem 1rem', fontSize: '11px', color: '#00d9ff', fontWeight: '700', textTransform: 'uppercase', letterSpacing: '1px' }}>Filter by Type</p>
              {filters.map(filter => (
                <button
                  key={filter.id}
                  onClick={() => setActiveFilter(filter.id)}
                  style={{
                    width: '100%',
                    padding: '0.875rem 1.5rem',
                    background: activeFilter === filter.id ? 'rgba(0,217,255,0.15)' : 'transparent',
                    color: activeFilter === filter.id ? '#00d9ff' : '#aaa',
                    border: 'none',
                    textAlign: 'left',
                    cursor: 'pointer',
                    fontSize: '14px',
                    fontWeight: activeFilter === filter.id ? '600' : '400',
                    borderLeft: activeFilter === filter.id ? '3px solid #00d9ff' : '3px solid transparent',
                    transition: 'all 0.2s'
                  }}
                >
                  <span style={{ marginRight: '0.5rem' }}>{filter.icon}</span> {filter.label}
                </button>
              ))}
            </div>

            <div style={{ position: 'absolute', bottom: '2rem', left: '1.5rem', right: '1.5rem' }}>
              <button style={{ width: '100%', padding: '0.875rem 1rem', background: 'linear-gradient(135deg, #00d9ff 0%, #0099ff 100%)', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: '13px' }}>Upgrade to Pro</button>
              <p style={{ margin: '0.75rem 0 0', fontSize: '12px', color: '#666' }}>Unlimited scans.<br/><strong style={{ color: '#aaa' }}>$29/mo</strong></p>
              <button onClick={() => { localStorage.removeItem('token'); setIsLoggedIn(false); setPage('landing'); }} style={{ marginTop: '1rem', width: '100%', padding: '0.75rem', background: 'transparent', color: '#ff6b6b', border: '1px solid rgba(255,107,107,0.3)', borderRadius: '6px', cursor: 'pointer', fontWeight: '600', fontSize: '12px' }}>Sign Out</button>
            </div>
          </div>
        )}

        {/* MAIN CONTENT */}
        <div style={{ flex: 1, padding: '2rem', overflowY: 'auto' }}>
          {/* TOP BAR */}
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
            <button onClick={() => setSidebarOpen(!sidebarOpen)} style={{ background: 'transparent', border: 'none', color: '#00d9ff', cursor: 'pointer', fontSize: '24px' }}>{sidebarOpen ? '✕' : '☰'}</button>
            <div style={{ position: 'relative', flex: 1, maxWidth: '400px', marginLeft: '1rem' }}>
              <Search size={18} style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)', color: '#666' }} />
              <input type="text" placeholder="Search or paste tickers..." value={scanInput} onChange={(e) => setScanInput(e.target.value)} style={{ width: '100%', padding: '0.75rem 1rem 0.75rem 2.75rem', borderRadius: '8px', border: '1px solid rgba(0,217,255,0.2)', background: 'rgba(10,10,20,0.5)', color: 'white', fontSize: '14px' }} />
            </div>
            <button onClick={handleScan} disabled={loading} style={{ marginLeft: '1rem', padding: '0.75rem 1.5rem', background: 'linear-gradient(135deg, #00d9ff 0%, #0099ff 100%)', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: '14px', opacity: loading ? 0.5 : 1 }}>{loading ? 'Scanning...' : 'Scan'}</button>
          </div>

          {/* RESULTS GRID - 2x2 */}
          {scanResults.length > 0 && (
            <>
              <h2 style={{ margin: '1rem 0 2rem', fontSize: '24px', fontWeight: '700' }}>Trading Setups</h2>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(500px, 1fr))', gap: '2rem', marginBottom: '3rem' }}>
                {scanResults.slice(0, 4).map((stock, i) => (
                  <div key={i} onClick={() => { setSelectedStock(stock); setChartData(generateChartData()); }} style={{ background: 'rgba(0,217,255,0.05)', border: '1px solid rgba(0,217,255,0.2)', borderRadius: '12px', padding: '1.5rem', cursor: 'pointer', transition: 'all 0.3s' }} onMouseEnter={(e) => { e.currentTarget.style.background = 'rgba(0,217,255,0.1)'; e.currentTarget.style.borderColor = 'rgba(0,217,255,0.4)'; }} onMouseLeave={(e) => { e.currentTarget.style.background = 'rgba(0,217,255,0.05)'; e.currentTarget.style.borderColor = 'rgba(0,217,255,0.2)'; }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', marginBottom: '1rem' }}>
                      <div>
                        <h3 style={{ margin: '0 0 0.25rem', fontSize: '22px', fontWeight: '800' }}>{stock.ticker}</h3>
                        <p style={{ margin: 0, color: '#00d9ff', fontSize: '12px', fontWeight: '600' }}>${stock.price}</p>
                      </div>
                      <button onClick={(e) => { e.stopPropagation(); toggleWatchlist(stock.ticker); }} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: '22px', color: watchlist.includes(stock.ticker) ? '#ff6b6b' : '#666', transition: 'all 0.2s' }}>♡</button>
                    </div>

                    <div style={{ marginBottom: '1rem' }}>
                      <p style={{ margin: 0, color: stock.change > 0 ? '#4ade80' : '#ff6b6b', fontWeight: '700', fontSize: '18px' }}>
                        {stock.change > 0 ? '▲' : '▼'} {stock.change}% ({stock.percentChange}%)
                      </p>
                    </div>

                    {/* MINI CHART */}
                    <ResponsiveContainer width="100%" height={120}>
                      <LineChart data={generateChartData()}>
                        <CartesianGrid strokeDasharray="3 3" stroke="rgba(0,217,255,0.1)" />
                        <XAxis dataKey="time" stroke="#666" style={{ fontSize: '10px' }} />
                        <YAxis stroke="#666" style={{ fontSize: '10px' }} />
                        <Line type="monotone" dataKey="price" stroke="#00d9ff" strokeWidth={2} dot={false} />
                      </LineChart>
                    </ResponsiveContainer>

                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '1rem', marginTop: '1rem', paddingTop: '1rem', borderTop: '1px solid rgba(0,217,255,0.1)' }}>
                      <div>
                        <p style={{ margin: '0 0 0.25rem', color: '#666', fontSize: '10px', fontWeight: '600', textTransform: 'uppercase' }}>RSI</p>
                        <p style={{ margin: 0, color: stock.rsi > 70 ? '#ff6b6b' : stock.rsi < 30 ? '#4ade80' : '#00d9ff', fontSize: '14px', fontWeight: '700' }}>{stock.rsi}</p>
                      </div>
                      <div>
                        <p style={{ margin: '0 0 0.25rem', color: '#666', fontSize: '10px', fontWeight: '600', textTransform: 'uppercase' }}>SIGNAL</p>
                        <p style={{ margin: 0, color: '#00d9ff', fontSize: '14px', fontWeight: '700' }}>{stock.signal}</p>
                      </div>
                      <div>
                        <p style={{ margin: '0 0 0.25rem', color: '#666', fontSize: '10px', fontWeight: '600', textTransform: 'uppercase' }}>VOLUME</p>
                        <p style={{ margin: 0, color: '#aaa', fontSize: '14px', fontWeight: '700' }}>{(stock.volume / 1000000).toFixed(1)}M</p>
                      </div>
                    </div>

                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem', marginTop: '1rem' }}>
                      {stock.gapUp && <span style={{ background: 'rgba(74,222,128,0.2)', color: '#4ade80', padding: '0.25rem 0.75rem', borderRadius: '4px', fontSize: '10px', fontWeight: '600' }}>Gap Up</span>}
                      {stock.breakout && <span style={{ background: 'rgba(0,217,255,0.2)', color: '#00d9ff', padding: '0.25rem 0.75rem', borderRadius: '4px', fontSize: '10px', fontWeight: '600' }}>Breakout</span>}
                      {stock.oversold && <span style={{ background: 'rgba(139,92,246,0.2)', color: '#c4b5fd', padding: '0.25rem 0.75rem', borderRadius: '4px', fontSize: '10px', fontWeight: '600' }}>Oversold</span>}
                    </div>
                  </div>
                ))}
              </div>
            </>
          )}

          {scanResults.length === 0 && (
            <div style={{ textAlign: 'center', padding: '4rem 2rem', color: '#666' }}>
              <TrendingUp size={48} style={{ margin: '0 auto 1rem', opacity: 0.3 }} />
              <p style={{ fontSize: '18px', margin: 0 }}>Enter stock tickers above to scan for trading setups</p>
              <p style={{ fontSize: '14px', color: '#444', margin: '0.5rem 0 0' }}>Example: AAPL,MSFT,GOOGL,TSLA</p>
            </div>
          )}
        </div>
      </div>
    );
  }

  return null;
};

export default App;
